/// Clients MAY periodically sync their local input state — the message the user
/// is composing, including its {@link Message.model | model} /
/// {@link Message.agent | agent} selection and attachments — into the chat's
/// {@link ChatState.draft | `draft`} so it survives reloads and is visible to
/// other clients viewing the same chat. Eager syncing is **not** required;
/// clients SHOULD debounce and MAY sync only at convenient points. Set `draft`
/// to `undefined` to clear it (e.g. once the message is sent).
///
/// A client is only allowed to draft {@link MessageKind.User} messages.</summary>
public sealed record ChatDraftChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>New draft message, or `undefined` to clear it</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Message? Draft { get; init; }
}

/// <summary>A session requested input from the user.
///
/// Full-request upsert semantics: the `request` replaces any existing request
/// with the same `id`, or is appended if it is new. Answer drafts are preserved
/// unless `request.answers` is provided.</summary>
public sealed record ChatInputRequestedAction
{
    public ActionType Type { get; init; }

    /// <summary>Input request to create or replace</summary>
    public required ChatInputRequest Request { get; init; }
}

/// <summary>A client updated, submitted, skipped, or removed a single in-progress answer.
///
/// Dispatching with `answer: undefined` removes that question's answer draft.</summary>
public sealed record ChatInputAnswerChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>Input request identifier</summary>
    public required string RequestId { get; init; }

    /// <summary>Question identifier within the input request</summary>
    public required string QuestionId { get; init; }

    /// <summary>Updated answer, or `undefined` to clear an answer draft</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChatInputAnswer? Answer { get; init; }
}

/// <summary>A client accepted, declined, or cancelled a session input request.
///
/// If accepted, the server uses `answers` (when provided) plus the request's
/// synced answer state to resume the blocked operation.</summary>
public sealed record ChatInputCompletedAction
{
    public ActionType Type { get; init; }

    /// <summary>Input request identifier</summary>
    public required string RequestId { get; init; }

    /// <summary>Completion outcome</summary>
    public ChatInputResponseKind Response { get; init; }

    /// <summary>Optional final answer replacement, keyed by question ID</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, ChatInputAnswer>? Answers { get; init; }
}

/// <summary>The {@link ChangesetState.status} for this changeset transitioned (e.g.
/// `computing → ready`). The error payload is set together with `status`
/// whenever it transitions to {@link ChangesetStatus.Error | Error}.</summary>
public sealed record ChangesetStatusChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>New computation lifecycle status.</summary>
    public ChangesetStatus Status { get; init; }

    /// <summary>Cause when `status === ChangesetStatus.Error`; otherwise omitted.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? Error { get; init; }
}

/// <summary>Upsert a {@link ChangesetFile} in the changeset — adds a new entry, or
/// replaces an existing one identified by {@link ChangesetFile.id}.</summary>
public sealed record ChangesetFileSetAction
{
    public ActionType Type { get; init; }

    /// <summary>The new or replacement file entry.</summary>
    public required ChangesetFile File { get; init; }
}

/// <summary>Remove a {@link ChangesetFile} from the changeset by its id.
///
/// Typically dispatched when a file is reverted, staged out, or otherwise
/// no longer in scope (e.g. a renamed file is replaced by a new entry).</summary>
public sealed record ChangesetFileRemovedAction
{
    public ActionType Type { get; init; }

    /// <summary>The {@link ChangesetFile.id} of the file to remove.</summary>
    public required string FileId { get; init; }
}

/// <summary>The changeset's full content changed. Full replacement semantics: `files`
/// replaces the previous file list, and `operations`, when present, replaces
/// the previous operation list.
///
/// Producers SHOULD use this action for initial snapshots and bulk refreshes;
/// use {@link ChangesetFileSetAction}, {@link ChangesetFileRemovedAction}, and
/// {@link ChangesetOperationsChangedAction} for incremental updates.</summary>
public sealed record ChangesetContentChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>Full replacement file list.</summary>
    public required List<ChangesetFile> Files { get; init; }

    /// <summary>Full replacement operation list. Omit when operations are unchanged.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<ChangesetOperation>? Operations { get; init; }

    /// <summary>Error information, if the changeset content change failed.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? Error { get; init; }
}

/// <summary>The set of operations available on this changeset changed. Full
/// replacement semantics: `operations` replaces the previous list (or
/// removes it entirely when `operations` is `undefined`).</summary>
public sealed record ChangesetOperationsChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>Updated operation list. Pass `undefined` to clear all operations.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<ChangesetOperation>? Operations { get; init; }
}

/// <summary>The {@link ChangesetOperation.status} for a single operation transitioned
/// (e.g. `idle → running → idle`, or `running → error`). The error payload
/// is set together with `status` whenever it transitions to
/// {@link ChangesetOperationStatus.Error | Error}, and cleared on any other
/// transition.
///
/// Targets one operation by its {@link ChangesetOperation.id}. If no
/// operation with that id is currently present in the changeset, the action
/// is a no-op. Use {@link ChangesetOperationsChangedAction} to add, remove,
/// or otherwise replace the operation list itself.</summary>
public sealed record ChangesetOperationStatusChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>The {@link ChangesetOperation.id} whose status changed.</summary>
    public required string OperationId { get; init; }

    /// <summary>New execution status.</summary>
    public ChangesetOperationStatus Status { get; init; }

    /// <summary>Cause when `status === ChangesetOperationStatus.Error`; otherwise omitted.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? Error { get; init; }
}

/// <summary>Drop every file from the changeset.
///
/// Two cases use this:
/// 1. The underlying source moved (branch switched, fork point invalidated,
///    …) and the server is recomputing from scratch — subsequent
///    {@link ChangesetFileSetAction} entries will repopulate it.
/// 2. The owning session has ended and the URI is becoming
///    un-subscribable — the server will unsubscribe all clients shortly
///    after dispatching this action.
///
/// Clients SHOULD release any references on receipt and SHOULD NOT
/// distinguish the two cases from the action alone — instead, react to
/// the corresponding session-level lifecycle signal (e.g.
/// `root/sessionRemoved`) for the "going away" case.</summary>
public sealed record ChangesetClearedAction
{
    public ActionType Type { get; init; }
}

/// <summary>Fired when the list of known terminals changes.
///
/// Full-replacement semantics: the `terminals` array replaces the previous
/// `terminals` entirely.</summary>
public sealed record RootTerminalsChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>Updated terminal list (full replacement)</summary>
    public required List<TerminalInfo> Terminals { get; init; }
}

/// <summary>Terminal output data (pty → client direction).
///
/// Appends `data` to the terminal's `content` in the reducer.
///
/// `terminal/data` and `terminal/input` are intentionally separate actions
/// because standard write-ahead reconciliation is not safe for terminal I/O.
/// A pty is a stateful, mutable process — optimistically applying input or
/// predicting output would produce incorrect state. Instead, `terminal/input`
/// is a side-effect-only action (client → server → pty), and `terminal/data`
/// is server-authoritative output (pty → server → client).</summary>
public sealed record TerminalDataAction
{
    public ActionType Type { get; init; }

    /// <summary>Output data (may contain ANSI escape sequences)</summary>
    public required string Data { get; init; }
}

/// <summary>Keyboard input sent to the terminal process (client → pty direction).
///
/// This is a side-effect-only action: the server forwards the data to the
/// terminal's pty. The reducer treats this as a no-op since `terminal/data`
/// actions will reflect any resulting output.
///
/// See `terminal/data` for why these two actions are kept separate.</summary>
public sealed record TerminalInputAction
{
    public ActionType Type { get; init; }

    /// <summary>Input data to send to the pty</summary>
    public required string Data { get; init; }
}

/// <summary>Terminal dimensions changed.
///
/// Dispatchable by clients to request a resize, or by the server to inform
/// clients of the actual terminal dimensions.</summary>
public sealed record TerminalResizedAction
{
    public ActionType Type { get; init; }

    /// <summary>Terminal width in columns</summary>
    public long Cols { get; init; }

    /// <summary>Terminal height in rows</summary>
    public long Rows { get; init; }
}

/// <summary>Terminal claim changed. A client or session transfers ownership of the terminal.
///
/// The server SHOULD reject if the dispatching client does not currently hold
/// the claim.</summary>
public sealed record TerminalClaimedAction
{
    public ActionType Type { get; init; }

    /// <summary>The new claim</summary>
    public required TerminalClaim Claim { get; init; }
}

/// <summary>Terminal title changed.
///
/// Fired by the server when the terminal process updates its title (e.g. via
/// escape sequences), or dispatched by a client to rename a terminal.</summary>
public sealed record TerminalTitleChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>New terminal title</summary>
    public required string Title { get; init; }
}

/// <summary>Terminal working directory changed.</summary>
public sealed record TerminalCwdChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>New working directory</summary>
    public required string Cwd { get; init; }
}

/// <summary>Terminal process exited.</summary>
public sealed record TerminalExitedAction
{
    public ActionType Type { get; init; }

    /// <summary>Process exit code. `undefined` if the process was killed without an exit code.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? ExitCode { get; init; }
}

/// <summary>Terminal scrollback buffer cleared.</summary>
public sealed record TerminalClearedAction
{
    public ActionType Type { get; init; }
}

/// <summary>Shell integration has loaded and the terminal now supports command
/// detection. The server dispatches this when shell integration becomes
/// available (which may happen asynchronously after the terminal is created).
///
/// Clients MUST NOT assume command detection is available until this action
/// (or `terminal/commandExecuted`) has been received.</summary>
public sealed record TerminalCommandDetectionAvailableAction
{
    public ActionType Type { get; init; }
}

/// <summary>A command has been submitted to the shell and is now executing.
/// All subsequent `terminal/data` actions (until the matching
/// `terminal/commandFinished`) constitute this command's output.</summary>
public sealed record TerminalCommandExecutedAction
{
    public ActionType Type { get; init; }

    /// <summary>Stable identifier for this command, scoped to the terminal URI.
    /// Allows correlating `commandExecuted` → `commandFinished` pairs.</summary>
    public required string CommandId { get; init; }

    /// <summary>The command line text that was submitted</summary>
    public required string CommandLine { get; init; }

    /// <summary>Unix timestamp (ms) of when the command started executing, as measured
    /// on the server.</summary>
    public long Timestamp { get; init; }
}

/// <summary>A command has finished executing.
///
/// The sequence of `terminal/data` actions between the preceding
/// `terminal/commandExecuted` (same `commandId`) and this action constitutes
/// the complete output of the command.</summary>
public sealed record TerminalCommandFinishedAction
{
    public ActionType Type { get; init; }

    /// <summary>Matches the `commandId` from the corresponding `commandExecuted`</summary>
    public required string CommandId { get; init; }

    /// <summary>Shell exit code. `undefined` if the shell did not report one.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? ExitCode { get; init; }

    /// <summary>Wall-clock duration of the command in milliseconds, as measured by the
    /// shell integration script on the server side.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? DurationMs { get; init; }
}

/// <summary>A batch of resource changes observed by the watcher.
///
/// Watch events are coalesced into batches by the server to keep the
/// action stream tractable; an empty `changes.items` list MUST NOT be
/// dispatched. The reducer does not retain change history — these
/// actions exist purely to deliver events to subscribers, who consume
/// them directly off the action stream and apply their own logic.</summary>
public sealed record ResourceWatchChangedAction
{
    public ActionType Type { get; init; }

    /// <summary>The set of changes in this batch, wrapped for forward compatibility.</summary>
    public JsonElement Changes { get; init; }
}

/// <summary>Upsert an {@link Annotation} in the annotations channel — adds a new
/// annotation, or replaces an existing one identified by
/// {@link Annotation.id}.
///
/// Dispatched by a client to create an annotation (together with its
/// mandatory first entry) or to re-anchor / resolve an existing one; the
/// dispatching client assigns the {@link Annotation.id} and the id of any
/// new entry. When replacing, the full annotation payload (including its
/// {@link Annotation.entries | entries} list) is substituted; producers
/// SHOULD prefer {@link AnnotationsEntrySetAction} for per-entry edits, and
/// {@link AnnotationsUpdatedAction} to resolve / re-anchor an existing
/// annotation, to keep wire updates small.</summary>
public sealed record AnnotationsSetAction
{
    public ActionType Type { get; init; }

    /// <summary>The new or replacement annotation. MUST contain at least one entry.</summary>
    public required Annotation Annotation { get; init; }
}

/// <summary>Remove an {@link Annotation} from the channel by its id.
///
/// Dispatched to delete an entire annotation and every entry it contains.
/// Because the protocol forbids empty annotations, a client that wants to
/// remove the last remaining entry dispatches this action — collapsing the
/// annotation — rather than {@link AnnotationsEntryRemovedAction}.</summary>
public sealed record AnnotationsRemovedAction
{
    public ActionType Type { get; init; }

    /// <summary>The {@link Annotation.id} of the annotation to remove.</summary>
    public required string AnnotationId { get; init; }
}

/// <summary>Upsert an {@link AnnotationEntry} within an existing annotation — adds a
/// new entry, or replaces one identified by {@link AnnotationEntry.id}. The
/// dispatching client assigns the {@link AnnotationEntry.id} of a new entry.
/// If {@link annotationId} does not match any current annotation the action
/// is a no-op.</summary>
public sealed record AnnotationsEntrySetAction
{
    public ActionType Type { get; init; }

    /// <summary>The {@link Annotation.id} the entry belongs to.</summary>
    public required string AnnotationId { get; init; }

    /// <summary>The new or replacement entry.</summary>
    public required AnnotationEntry Entry { get; init; }
}

/// <summary>Remove a single {@link AnnotationEntry} from an annotation without
/// collapsing the annotation itself. Used when more than one entry remains —
/// to remove the last entry a client dispatches {@link AnnotationsRemovedAction}
/// instead, since the protocol forbids empty annotations.
///
/// If either {@link annotationId} or {@link entryId} does not match the
/// current state the action is a no-op.</summary>
public sealed record AnnotationsEntryRemovedAction
{
    public ActionType Type { get; init; }

    /// <summary>The {@link Annotation.id} the entry belongs to.</summary>
    public required string AnnotationId { get; init; }

    /// <summary>The {@link AnnotationEntry.id} to remove.</summary>
    public required string EntryId { get; init; }
}

/// <summary>Partially update an existing {@link Annotation}'s own properties — a narrow
/// alternative to {@link AnnotationsSetAction} for the common case of resolving
/// / re-opening or re-anchoring an annotation without resending its
/// {@link Annotation.entries | entries}.
///
/// Targets one annotation by its {@link annotationId}. Only the fields present
/// on the action are written; omitted fields leave the corresponding
/// {@link Annotation} property unchanged. The annotation's
/// {@link Annotation.entries | entries}, {@link Annotation.id | id}, and
/// {@link Annotation._meta | _meta} are never touched — dispatch
/// {@link AnnotationsSetAction} to replace those, to clear {@link range}
/// (re-anchor to the whole file), or {@link AnnotationsEntrySetAction} /
/// {@link AnnotationsEntryRemovedAction} to edit individual entries.
///
/// If {@link annotationId} does not match any current annotation the action is
/// a no-op.</summary>
public sealed record AnnotationsUpdatedAction
{
    public ActionType Type { get; init; }

    /// <summary>The {@link Annotation.id} of the annotation to update.</summary>
    public required string AnnotationId { get; init; }

    /// <summary>Re-anchors the annotation to the file versions this turn produced.
    /// Matches a {@link Turn.id} on the owning session. Omit to leave the
    /// current {@link Annotation.turnId} unchanged.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? TurnId { get; init; }

    /// <summary>Re-anchors the annotation to this file. Omit to leave the current
    /// {@link Annotation.resource} unchanged.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Resource { get; init; }

    /// <summary>Narrows the annotation to this range within {@link resource}. Omit to
    /// leave the current {@link Annotation.range} unchanged; this action cannot
    /// clear an existing range — dispatch {@link AnnotationsSetAction} to
    /// re-anchor to the whole file.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public TextRange? Range { get; init; }

    /// <summary>Marks the annotation resolved (`true`) or re-opens it (`false`). Omit to
    /// leave the current {@link Annotation.resolved} state unchanged.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? Resolved { get; init; }
}

// ─── Partial Summaries (action-discovered) ───────────────────────────

/// <summary>Partial equivalent of ChatSummary — every field is optional for delta updates.</summary>
public sealed record PartialChatSummary
{
    /// <summary>Chat URI</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Resource { get; init; }

    /// <summary>Chat title</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Title { get; init; }

    /// <summary>Current chat status (reuses SessionStatus shape)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public SessionStatus? Status { get; init; }

    /// <summary>Human-readable description of what the chat is currently doing</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Activity { get; init; }

    /// <summary>Last modification timestamp (ISO 8601, e.g. `"2025-03-10T18:42:03.123Z"`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? ModifiedAt { get; init; }

    /// <summary>How this chat came into existence</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChatOrigin? Origin { get; init; }

    /// <summary>How the user can interact with this chat. See {@link ChatInteractivity}.
    ///
    /// Supports agent-team patterns where worker chats are read-only or hidden.
    /// Absence defaults to {@link ChatInteractivity.Full} for backward
    /// compatibility.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChatInteractivity? Interactivity { get; init; }

    /// <summary>Optional per-chat working directory.
    ///
    /// If absent, the chat inherits
    /// {@link SessionSummary.workingDirectory | the session's working directory}.
    /// See {@link ChatState.workingDirectory} for usage notes.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? WorkingDirectory { get; init; }
}

