        ["chat/turnStarted"] = typeof(ChatTurnStartedAction),
        ["chat/delta"] = typeof(ChatDeltaAction),
        ["chat/responsePart"] = typeof(ChatResponsePartAction),
        ["chat/toolCallStart"] = typeof(ChatToolCallStartAction),
        ["chat/toolCallDelta"] = typeof(ChatToolCallDeltaAction),
        ["chat/toolCallReady"] = typeof(ChatToolCallReadyAction),
        ["chat/toolCallConfirmed"] = typeof(ChatToolCallConfirmedAction),
        ["chat/toolCallComplete"] = typeof(ChatToolCallCompleteAction),
